CREATE PROCEDURE rsdev444_reseed_hibernate_sequences()
BEGIN
    DECLARE v_done   INT DEFAULT 0;
    DECLARE v_seg    VARCHAR(255);
    DECLARE v_is_tbl INT DEFAULT 0;
    DECLARE v_global BIGINT DEFAULT 0;
    DECLARE seg_cur CURSOR FOR SELECT sequence_name FROM hibernate_sequences;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = 1;

    -- 1) Per-entity (table-named) segments: bump each above its own table's MAX(id).
    OPEN seg_cur;
    seg_loop: LOOP
        FETCH seg_cur INTO v_seg;
        IF v_done = 1 THEN
            LEAVE seg_loop;
        END IF;

        SELECT COUNT(*) INTO v_is_tbl
        FROM information_schema.COLUMNS
        WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = v_seg AND COLUMN_NAME = 'id';

        IF v_is_tbl = 1 THEN
            SET @m := 0;
            SET @q := CONCAT('SELECT COALESCE(MAX(id),0) INTO @m FROM `', v_seg, '`');
            PREPARE s FROM @q;
            EXECUTE s;
            DEALLOCATE PREPARE s;

            IF @m > 0 THEN
                UPDATE hibernate_sequences
                SET next_val = @m + 51
                WHERE sequence_name = v_seg AND (next_val IS NULL OR next_val < @m + 51);
                IF @m > v_global THEN SET v_global = @m; END IF;
            END IF;
        END IF;
    END LOOP;
    CLOSE seg_cur;

    -- 2) TABLE_PER_CLASS: AbstractUserOrGroupImpl shares ids across User + rsGroup.
    SET @uog := GREATEST(
        COALESCE((SELECT MAX(id) FROM `User`), 0),
        COALESCE((SELECT MAX(id) FROM `rsGroup`), 0));
    IF @uog > 0 THEN
        INSERT INTO hibernate_sequences (sequence_name, next_val)
            SELECT 'AbstractUserOrGroupImpl', @uog + 51 FROM DUAL
            WHERE NOT EXISTS (SELECT 1 FROM hibernate_sequences WHERE sequence_name = 'AbstractUserOrGroupImpl');
        UPDATE hibernate_sequences
        SET next_val = @uog + 51
        WHERE sequence_name = 'AbstractUserOrGroupImpl' AND (next_val IS NULL OR next_val < @uog + 51);
        IF @uog > v_global THEN SET v_global = @uog; END IF;
    END IF;

    -- 3) TABLE_PER_CLASS: Communication shares ids across its concrete subclass tables.
    SET @comm := GREATEST(
        COALESCE((SELECT MAX(id) FROM `Notification`), 0),
        COALESCE((SELECT MAX(id) FROM `MessageOrRequest`), 0),
        COALESCE((SELECT MAX(id) FROM `GroupMessageOrRequest`), 0),
        COALESCE((SELECT MAX(id) FROM `CreateGroupMessageOrRequest`), 0),
        COALESCE((SELECT MAX(id) FROM `ShareRecordMessageOrRequest`), 0));
    IF @comm > 0 THEN
        INSERT INTO hibernate_sequences (sequence_name, next_val)
            SELECT 'Communication', @comm + 51 FROM DUAL
            WHERE NOT EXISTS (SELECT 1 FROM hibernate_sequences WHERE sequence_name = 'Communication');
        UPDATE hibernate_sequences
        SET next_val = @comm + 51
        WHERE sequence_name = 'Communication' AND (next_val IS NULL OR next_val < @comm + 51);
        IF @comm > v_global THEN SET v_global = @comm; END IF;
    END IF;

    -- 4) Insurance "default" segment above the global MAX(id) for the shared-segment fallback path.
    IF v_global > 0 THEN
        INSERT INTO hibernate_sequences (sequence_name, next_val)
            SELECT 'default', v_global + 51 FROM DUAL
            WHERE NOT EXISTS (SELECT 1 FROM hibernate_sequences WHERE sequence_name = 'default');
        UPDATE hibernate_sequences
        SET next_val = v_global + 51
        WHERE sequence_name = 'default' AND (next_val IS NULL OR next_val < v_global + 51);
    END IF;
END
